let slide=document.getElementById('slide-content');document.getElementById("next-slide").addEventListener("click",function(){let a=slide.getAttribute('data-slide'),b=parseInt(slide.getAttribute('data-max'));if(a<b){let b=window.location.href+'slide/slide-'+(parseInt(a)+1)+'.jpg';slide.src=b,slide.setAttribute("data-slide",parseInt(a)+1)}}),document.getElementById("prev-slide").addEventListener("click",function(){let a=slide.getAttribute('data-slide');if(a>1){let b=window.location.href+'slide/slide-'+(parseInt(a)-1)+'.jpg';slide.src=b,slide.setAttribute("data-slide",parseInt(a)-1)}else{let b=window.location.href+'slide/slide-'+a+'.jpg';slide.src=b,slide.setAttribute("data-slide","1")}})